// Build the contacts array required by ScraperCity Email Finder
const contacts = items.map(item => ({
  first_name: (item.json.first_name || '').trim(),
  last_name:  (item.json.last_name  || '').trim(),
  domain:     (item.json.domain     || '').trim().replace(/^https?:\/\//, '').replace(/^www\./, '').split('/')[0]
})).filter(c => c.first_name && c.last_name && c.domain);

return [{ json: { contacts } }];

// Parse CSV from email-finder download
// Expected columns: first_name, last_name, domain, email, confidence
const raw = items[0].json.data || items[0].json.body || '';
if (!raw) return [];

const lines = raw.trim().split('\n');
if (lines.length < 2) return [];

const headers = lines[0].split(',').map(h => h.trim().replace(/^"|"$/g, ''));
const results = [];

for (let i = 1; i < lines.length; i++) {
  const cols = lines[i].split(',').map(c => c.trim().replace(/^"|"$/g, ''));
  if (cols.length < headers.length) continue;
  const row = {};
  headers.forEach((h, idx) => { row[h] = cols[idx] || ''; });
  if (row.email) results.push({ json: row });
}

return results;

// Mobile Finder accepts an array of email strings
const inputs = items
  .map(item => (item.json.email || '').trim().toLowerCase())
  .filter(e => e.includes('@'));

return [{ json: { inputs } }];

// Parse CSV from mobile-finder download
// Expected columns: input, phone, phone_type, country
const raw = items[0].json.data || items[0].json.body || '';
if (!raw) return [];

const lines = raw.trim().split('\n');
if (lines.length < 2) return [];

const headers = lines[0].split(',').map(h => h.trim().replace(/^"|"$/g, ''));
const results = [];

for (let i = 1; i < lines.length; i++) {
  const cols = lines[i].split(',').map(c => c.trim().replace(/^"|"$/g, ''));
  if (cols.length < headers.length) continue;
  const row = {};
  headers.forEach((h, idx) => { row[h] = cols[idx] || ''; });
  // Normalise: map 'input' -> 'email' so we can merge later
  row.email = row.input || row.email || '';
  results.push({ json: row });
}

return results;

// Email Validator accepts {"emails": ["user@example.com", ...]}
// We pull emails from the parsed email-finder results stored earlier
const emails = items
  .map(item => (item.json.email || '').trim().toLowerCase())
  .filter(e => e.includes('@'));

return [{ json: { emails } }];

// Parse CSV from email-validator download
// Expected columns: email, status, deliverability, catch_all, mx_found
const raw = items[0].json.data || items[0].json.body || '';
if (!raw) return [];

const lines = raw.trim().split('\n');
if (lines.length < 2) return [];

const headers = lines[0].split(',').map(h => h.trim().replace(/^"|"$/g, ''));
const results = [];

for (let i = 1; i < lines.length; i++) {
  const cols = lines[i].split(',').map(c => c.trim().replace(/^"|"$/g, ''));
  if (cols.length < headers.length) continue;
  const row = {};
  headers.forEach((h, idx) => { row[h] = cols[idx] || ''; });
  results.push({ json: row });
}

return results;

/**
 * Merge email-finder results, mobile-finder results, and validator results
 * by email address into a single enriched record per contact.
 *
 * This node must be triggered after all three downloads are complete.
 * It reads the outputs stored from the three parse steps.
 *
 * Since n8n Code nodes only receive items from the immediately connected
 * upstream node, we build a lookup from each stored array.
 *
 * The workflow passes all three arrays into this node via the Set node
 * "Prepare Merge Inputs" that precedes it.
 */

const emailRows     = JSON.parse($json.emailFinderRows   || '[]');
const mobileRows    = JSON.parse($json.mobileFinderRows  || '[]');
const validatorRows = JSON.parse($json.validatorRows     || '[]');

// Build lookup maps keyed by lowercase email
const mobileMap    = {};
const validatorMap = {};

for (const r of mobileRows) {
  const key = (r.email || '').toLowerCase();
  if (key) mobileMap[key] = r;
}
for (const r of validatorRows) {
  const key = (r.email || '').toLowerCase();
  if (key) validatorMap[key] = r;
}

const merged = emailRows.map(row => {
  const key     = (row.email || '').toLowerCase();
  const mobile  = mobileMap[key]    || {};
  const valid   = validatorMap[key] || {};
  return {
    json: {
      first_name:       row.first_name       || '',
      last_name:        row.last_name        || '',
      domain:           row.domain           || '',
      email:            row.email            || '',
      email_confidence: row.confidence       || '',
      phone:            mobile.phone         || '',
      phone_type:       mobile.phone_type    || '',
      phone_country:    mobile.country       || '',
      email_status:     valid.status         || '',
      deliverability:   valid.deliverability || '',
      catch_all:        valid.catch_all       || '',
      mx_found:         valid.mx_found        || ''
    }
  };
});

return merged;
